#include <stdio.h>
#include <stdlib.h>

struct Stack {
    int top;
    int capacity;
    int *data;
};

struct Stack* createStack(int cap) {
    struct Stack *s = (struct Stack*)malloc(sizeof(struct Stack));
    s->capacity = cap;
    s->top = -1;
    s->data = (int*)malloc(sizeof(int) * cap);
    return s;
}

int isEmpty(struct Stack *s) { return s->top == -1; }

int peek(struct Stack *s) { return s->data[s->top]; }

void push(struct Stack *s, int x) { s->data[++s->top] = x; }

void pop(struct Stack *s) { if (!isEmpty(s)) s->top--; }

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int n; scanf("%d", &n);
        int *arr = (int*)malloc(sizeof(int) * n);
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        int *nge = (int*)malloc(sizeof(int) * n);
        struct Stack *st = createStack(n);
        for (int i = n - 1; i >= 0; --i) {
            while (!isEmpty(st) && peek(st) <= arr[i]) pop(st);
            nge[i] = isEmpty(st) ? -1 : peek(st);
            push(st, arr[i]);
        }
        for (int i = 0; i < n; ++i) {
            printf("%d", nge[i]);
            if (i + 1 < n) printf(" ");
        }
        printf("\n");
        free(arr);
        free(nge);
        free(st->data);
        free(st);
    }
    return 0;
}

