import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        n = next(it)
        arr = [next(it) for _ in range(n)]
        nge = [-1] * n
        stack = []
        for i in range(n - 1, -1, -1):
            while stack and stack[-1] <= arr[i]:
                stack.pop()
            if stack:
                nge[i] = stack[-1]
            stack.append(arr[i])
        out_lines.append(' '.join(map(str, nge)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

